 ),                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                +
 total as (                                                                                                                                                                                                                                                                                     +
   select sum(revenue) as total_rev from agg                                                                                                                                                                                                                                                    +
 )                                                                                                                                                                                                                                                                                              +
                                                                                                                                                                                                                                                                                                +
 select                                                                                                                                                                                                                                                                                         +
   a.order_channel,                                                                                                                                                                                                                                                                             +
   a.revenue,                                                                                                                                                                                                                                                                                   +
   round(a.revenue / t.total_rev * 100,2) as share_pct                                                                                                                                                                                                                                          +
 from agg a, total t                                                                                                                                                                                                                                                                            +
 order by revenue desc;                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                +
