 -- analytics.get_sales_top_items                                                                                                                                                                                                                                                               +
 CREATE OR REPLACE FUNCTION analytics.get_sales_top_items(p_asof timestamp with time zone, p_window text, p_location uuid, p_limit integer)                                                                                                                                                     +
  RETURNS TABLE(item_name text, quantity bigint, revenue numeric, share_pct numeric)                                                                                                                                                                                                            +
  LANGUAGE sql                                                                                                                                                                                                                                                                                  +
 AS $function$                                                                                                                                                                                                                                                                                  +
                                                                                                                                                                                                                                                                                                +
 with params as (                                                                                                                                                                                                                                                                               +
   select                                                                                                                                                                                                                                                                                       +
     date(p_asof) as as_of_day,                                                                                                                                                                                                                                                                 +
     case                                                                                                                                                                                                                                                                                       +
       when p_window = '7d' then 7                                                                                                                                                                                                                                                              +
       when p_window = '30d' then 30                                                                                                                                                                                                                                                            +
       when p_window = '90d' then 90                                                                                                                                                                                                                                                            +
       when p_window = 'ytd' then extract(doy from date(p_asof))::int                                                                                                                                                                                                                           +
       else 30                                                                                                                                                                                                                                                                                  +
     end as win_days                                                                                                                                                                                                                                                                            +
 ),                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                +
 filtered as (                                                                                                                                                                                                                                                                                  +
   select *                                                                                                                                                                                                                                                                                     +
   from raw.sales_line_items r, params p                                                                                                                                                                                                                                                        +
   where r.business_date > p.as_of_day - p.win_days                                                                                                                                                                                                                                             +
     and r.business_date <= p.as_of_day                                                                                                                                                                                                                                                         +
 ),                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                +
 agg as (                                                                                                                                                                                                                                                                                       +
   select                                                                                                                                                                                                                                                                                       +
     item_name,                                                                                                                                                                                                                                                                                 +
     sum(quantity) as quantity,                                                                                                                                                                                                                                                                 +
     sum(net_sales) as revenue                                                                                                                                                                                                                                                                  +
   from filtered                                                                                                                                                                                                                                                                                +
   group by item_name                                                                                                                                                                                                                                                                           +
 ),                                                                                                                                                                                                                                                                                             +
                                                                                                                                                                                                                                                                                                +
 total as (                                                                                                                                                                                                                                                                                     +
   select sum(revenue) as total_rev from agg                                                                                                                                                                                                                                                    +
 )                                                                                                                                                                                                                                                                                              +
                                                                                                                                                                                                                                                                                                +
 select                                                                                                                                                                                                                                                                                         +
   a.item_name,                                                                                                                                                                                                                                                                                 +
   a.quantity,                                                                                                                                                                                                                                                                                  +
   a.revenue,                                                                                                                                                                                                                                                                                   +
   round(a.revenue / t.total_rev * 100,2) as share_pct                                                                                                                                                                                                                                          +
 from agg a, total t                                                                                                                                                                                                                                                                            +
 order by revenue desc                                                                                                                                                                                                                                                                          +
 limit p_limit;                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                     +
                                                                                                                                                                                                                                                                                                +
